use std::collections::HashMap;

struct Graph {
    adjacency_map: HashMap<String, Vec<String>>,
}

impl Graph {
    fn new() -> Self {
        Graph {
            adjacency_map: HashMap::new(),
        }
    }

    fn add_node(&mut self, node: &str) {
        if !self.adjacency_map.contains_key(node) {
            self.adjacency_map.insert(String::from(node), Vec::new());
        }
    }

    fn add_edge(&mut self, start_node: &str, end_node: &str) -> Result<(), String> {
        self.add_node(start_node);
        self.add_node(end_node);

        let mut neighbors = self.adjacency_map.get_mut(start_node).unwrap();
        if !neighbors.contains(&String::from(end_node)) {
            neighbors.push(String::from(end_node));
        }

        let mut other_neighbors = self.adjacency_map.get_mut(end_node).unwrap();
        if !other_neighbors.contains(&String::from(start_node)) {
            other_neighbors.push(String::from(start_node));
        }

        Ok(())
    }

    fn print_graph(&self) {
        println!("--- Graph Adjacency List ---");
        for (node, neighbors) in &self.adjacency_map {
            print!("\"{}\": [", node);
            let joined_neighbors: Vec<String> = neighbors.iter().cloned().collect();
            println!("{}", joined_neighbors.join(", "));
            println!("]");
        }
    }
}

fn main() {
    let mut study_graph = Graph::new();
    study_graph.add_edge("Deep Work", "Pomodoro Session").unwrap();
    study_graph.add_edge("Research Paper", "Writing Block").unwrap();
    study_graph.add_edge("Pomodoro Session", "Review Notes").unwrap();
    study_graph.add_edge("Writing Block", "Deep Work").unwrap();

    study_graph.print_graph();
}

use std::collections::{HashMap, HashSet, VecDeque};
use std::error::Error;

struct Graph {
    adj: HashMap<String, Vec<String>>,
}

impl Graph {
    fn new() -> Self {
        Graph { adj: HashMap::new() }
    }

    fn add_edge(&mut self, u: &str, v: &str) {
        self.adj.entry(u.to_string()).or_default().push(v.to_string());
        self.adj.entry(v.to_string()).or_default().push(u.to_string());
    }

    fn find_reachable(&self, start_node: &str) -> HashSet<String> {
        let mut visited = HashSet::new();
        let mut queue = VecDeque::new();
        queue.push_back(start_node.to_string());
        visited.insert(start_node.to_string());

        while let Some(current) = queue.pop_front() {
            if let Some(neighbors) = self.adj.get(&current) {
                for neighbor in neighbors { 
                    if !visited.contains(neighbor) {
                        visited.insert(neighbor.to_string());
                        queue.push_back(neighbor.clone());
                    }
                }
            }
        }
        visited
    }
}

