use std::collections::HashMap;

struct Graph {
    adj: HashMap<String, Vec<String>>,
}

impl Graph {
    fn new() -> Self {
        Graph { adj: HashMap::new() }
    }

    fn add_edge(&mut self, u: &str, v: &str) {
        self.adj.entry(u.to_string()).or_insert_with(Vec::new).push(v.to_string());
        self.adj.entry(v.to_string()).or_insert_with(Vec::new).push(u.to_string());
    }

    fn find_path(&self, start: &str, end: &str) -> Option<Vec<String>> {
        let mut visited = std::collections::HashSet::new();
        let mut queue = std::collections::VecDeque::new();
        queue.push_back(start.to_string());
        visited.insert(start.to_string());

        while let Some(current) = queue.pop_front() {
            if current == end { 
                let mut path = vec![end.to_string()];
                path.reverse();
                return Some(path);
            }

            for neighbor in self.adj.get(&current).unwrap() {
                if !visited.contains(neighbor) {
                    visited.insert(neighbor.clone());
                    queue.push_back(neighbor.clone());
                }
            }
        }
        None
    }
}

