#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
struct Vertex(i32, i32, i32);

fn find_connected_vertices(input_coords: &[(i32, i32, i32)]) -> HashMap<Vertex, Vec<(usize, Vertex)>> {
    let mut adjacency_map = HashMap::new();

    for i in 0..input_coords.len() { 
        let current_vertex = Vertex(input_coords[i].0, input_coords[i].1, input_coords[i].2);
        adjacency_map.entry(current_vertex).or_insert_with(Vec::new);
    }

    for i in 0..input_coords.len() { 
        let v = Vertex(input_coords[i].0, input_coords[i].1, input_coords[i].2);
        let mut neighbors = Vec::new();
        let mut visited_neighbors = HashSet::new();

        for j in 0..input_coords.len() { 
            if i == j { continue; }
            let neighbor_coord = input_coords[j];
            let neighbor_vertex = Vertex(neighbor_coord.0, neighbor_coord.1, neighbor_coord.2);

            if (input_coords[i].0 - neighbor_coord.0).abs() + 
               (input_coords[i].1 - neighbor_coord.1).abs() + 
               (input_coords[i].2 - neighbor_coord.2).abs() == 1 { 

                if !visited_neighbors.contains(&neighbor_vertex) {
                    neighbors.push((j, neighbor_vertex));
                    visited_neighbors.insert(neighbor_vertex);
                }
            }
        }
        adjacency_map.insert(v, neighbors);
    }

    adjacency_map
}

use std::collections::HashMap;
use std::sync::Mutex;

struct Node {
    id: u32,
    data: String,
    neighbors: Vec<u32>,
}

struct Graph {
    nodes: Mutex<HashMap<u32, Node>>
}

impl Graph {
    fn new() -> Self {
        Graph {
            nodes: Mutex::new(HashMap::new())
        }
    }

    fn add_node(&self, id: u32, data: String) -> Result<(), &'static str> {
        let mut nodes = self.nodes.lock().unwrap();
        if nodes.contains_key(&id) {
            return Err("Node already exists");
        }
        nodes.insert(id, Node { id, data, neighbors: Vec::new() });
        Ok(())
    }

    fn add_edge(&self, from_id: u32, to_id: u32) -> Result<(), &'static str> {
        let mut nodes = self.nodes.lock().unwrap();
        if !nodes.contains_key(&from_id) || !nodes.contains_key(&to_id) {
            return Err("One or both nodes do not exist");
        }

        let from_node = nodes.get_mut(&from_id).unwrap();
        if !from_node.neighbors.contains(&to_id) {
            from_node.neighbors.push(to_id);
        }

        let to_node = nodes.get_mut(&to_id).unwrap();
        if !to_node.neighbors.contains(&from_id) {
            to_node.neighbors.push(from_id);
        }
        Ok(())
    }

    fn print_graph(&self) {
        let nodes = self.nodes.lock().unwrap();
        println!("--- Graph Contents ---n");
        for node in nodes.values() {
            println!("Node {}: Data: {}", node.id, node.data);
            println!("  Neighbors: {:?}", node.neighbors);
        }
    }
}

fn main() {
    let graph = Graph::new();
    graph.add_node(101, String::from("Start Point")).unwrap();
    graph.add_node(202, String::from("Mid Hub")).unwrap();
    graph.add_node(303, String::from("End Destination")).unwrap();

    graph.add_edge(101, 202).unwrap();
    graph.add_edge(202, 303).unwrap();
    graph.add_edge(101, 303).unwrap();

    graph.print_graph();
}
